# coding: utf-8

import json

import click
from tabulate import tabulate

from rainbow_admin.cli import info

ENV_HEADER = [
    "env_name",
    "env_type",
    "description",
]


def format_config(env):
    return [
        env["env_name"],
        env["env_type"],
        env["env_desc"],
    ]


@click.group(name="env")
@click.pass_context
def env_cli(ctx):
    """actions about env"""


@env_cli.command(help="list env")
@click.option(
    "-f",
    "--format",
    default="table",
    help="result format",
    type=click.Choice(["table", "json"]),
)
@click.pass_context
def ls(ctx, format):
    admin = ctx.obj["admin"]

    env_list = admin.query_env_list()
    data = [format_config(i) for i in env_list]
    if format == "table":
        info(f"app_id={admin.app_id} envs:")
        click.echo(tabulate(data, ENV_HEADER, tablefmt="pretty"))
    elif format == "json":
        click.echo(json.dumps(env_list, ensure_ascii=False, indent=4))
